mapper.select:
/* mapper.member.com.erns.coching.MemberWithdrawInfoDAO.load */

SELECT

FROM T_MEMB_WTHDR_INF AA

	AND AA.WTHDR_SEQ	= #{value	, jdbcType=INTEGER}

/* mapper.member.com.erns.coching.MemberWithdrawInfoDAO.loadByMembSeq */

SELECT

FROM T_MEMB_WTHDR_INF AA

	AND AA.MEMB_SEQ 	= #{value	, jdbcType=INTEGER}
	AND ROWNUM = 1

mapper.insert:
/* mapper.member.com.erns.coching.MemberWithdrawInfoDAO.insert */


	SELECT nextval('seq_t_memb_wthdr_inf')


INSERT INTO T_MEMB_WTHDR_INF (
	  WTHDR_SEQ
	, MEMB_SEQ

	, WTHDR_RSN
	, WTHDR_RSN_TXT
	, DEL_ACNT
	, DEL_INTRL

	, RGTR
	, RGT_DTTM
)
VALUES (
	  #{seq		, jdbcType=INTEGER}
	, #{membSeq	, jdbcType=INTEGER}

	, #{withdrawReason		, jdbcType=VARCHAR}
	, #{withdrawReasonTxt	, jdbcType=VARCHAR}
	, #{delAccountAgreeYn	, jdbcType=CHAR}
	, #{delLinkInfoYn		, jdbcType=CHAR}

	, #{rgtr	, jdbcType=INTEGER}
	, now()
)
